{
  "name": "StyleMind - AI Personal Wardrobe",
  "description": "A smart digital wardrobe that analyzes your clothes and recommends the perfect outfit for any occasion using Gemini AI.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ClothingCategory {
  SHIRT = 'shirt',
  PANTS = 'pants',
  ACCESSORY = 'accessory',
  SHOES = 'shoes',
  OTHER = 'other'
}

export interface ClothingItem {
  id: string;
  image: string; // base64
  category: ClothingCategory;
  color: string;
  material: string;
  pattern: string;
  style: string;
  season: string;
  description: string;
}

export interface RecommendedOutfit {
  items: ClothingItem[];
  explanation: string;
}

export type View = 'onboarding' | 'wardrobe' | 'recommend';

import { GoogleGenAI, Type } from "@google/genai";
import { ClothingItem, ClothingCategory } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeClothingImage = async (base64Image: string): Promise<Partial<ClothingItem>[]> => {
  const model = 'gemini-3-flash-preview';

  const prompt = `Analyze this image and identify all clothing items present. 
  For each item found, provide details in JSON format.
  If multiple items are shown (e.g., several shirts or an outfit), list each one separately.

  Format the response as a JSON array of objects. Each object should have:
  - category: one of 'shirt', 'pants', 'accessory', 'shoes', 'other'
  - color: primary color
  - material: likely material
  - pattern: e.g., solid, striped, plaid, etc.
  - style: casual, formal, sporty, business-casual, etc.
  - season: spring, summer, fall, winter, or all-season
  - description: a concise 1-sentence description.`;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image.split(',')[1] || base64Image } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            category: { type: Type.STRING, enum: Object.values(ClothingCategory) },
            color: { type: Type.STRING },
            material: { type: Type.STRING },
            pattern: { type: Type.STRING },
            style: { type: Type.STRING },
            season: { type: Type.STRING },
            description: { type: Type.STRING },
          },
          required: ["category", "color", "description"]
        }
      }
    }
  });

  try {
    const data = JSON.parse(response.text);
    return data;
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    return [];
  }
};

export const getOutfitRecommendation = async (
  wardrobe: ClothingItem[],
  userPrompt: string
): Promise<{ itemIds: string[]; explanation: string } | null> => {
  const model = 'gemini-3-flash-preview';

  const prompt = `You are a professional fashion stylist.
  Based on the user's wardrobe provided below and their specific request, recommend the best combination of items.

  WARDROBE:
  ${JSON.stringify(wardrobe.map(item => ({ id: item.id, ...item, image: undefined })))}

  USER REQUEST:
  "${userPrompt}"

  Please select 2-4 items that go together perfectly for this situation.
  Return a JSON object with:
  - itemIds: an array of strings corresponding to the item IDs selected.
  - explanation: why this outfit works for the requested occasion.`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          itemIds: { type: Type.ARRAY, items: { type: Type.STRING } },
          explanation: { type: Type.STRING }
        },
        required: ["itemIds", "explanation"]
      }
    }
  });

  try {
    return JSON.parse(response.text);
  } catch (e) {
    console.error("Failed to parse recommendation", e);
    return null;
  }
};

import React, { useState, useEffect } from 'react';
import { View, ClothingItem, ClothingCategory } from './types';
import Onboarding from './components/Onboarding';
import WardrobeGrid from './components/WardrobeGrid';
import OutfitRecommender from './components/OutfitRecommender';
import { Layout, Shirt, LayoutGrid, Sparkles } from 'lucide-react';

const STORAGE_KEY = 'stylemind_wardrobe';

const App: React.FC = () => {
  const [view, setView] = useState<View>('onboarding');
  const [wardrobe, setWardrobe] = useState<ClothingItem[]>([]);
  const [loading, setLoading] = useState(false);

  // Load wardrobe from localStorage
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      const items = JSON.parse(saved);
      setWardrobe(items);

      // Check if onboarding requirements are met
      const hasShirt = items.some((i: ClothingItem) => i.category === ClothingCategory.SHIRT);
      const hasPants = items.some((i: ClothingItem) => i.category === ClothingCategory.PANTS);

      if (hasShirt && hasPants) {
        setView('wardrobe');
      }
    }
  }, []);

  // Save wardrobe to localStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(wardrobe));
  }, [wardrobe]);

  const addItems = (newItems: ClothingItem[]) => {
    setWardrobe(prev => [...prev, ...newItems]);
  };

  const deleteItem = (id: string) => {
    setWardrobe(prev => prev.filter(item => item.id !== id));
  };

  const updateItem = (updated: ClothingItem) => {
    setWardrobe(prev => prev.map(item => item.id === updated.id ? updated : item));
  };

  const finishOnboarding = () => {
    setView('wardrobe');
  };

  return (
    <div className="flex flex-col min-h-screen bg-slate-50">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-indigo-200">
            <Shirt size={24} />
          </div>
          <h1 className="text-xl font-bold tracking-tight text-slate-800">StyleMind</h1>
        </div>

        {view !== 'onboarding' && (
          <nav className="flex gap-1 bg-slate-100 p-1 rounded-lg">
            <button 
              onClick={() => setView('wardrobe')}
              className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-all ${view === 'wardrobe' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-800'}`}
            >
              <LayoutGrid size={16} />
              Wardrobe
            </button>
            <button 
              onClick={() => setView('recommend')}
              className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-all ${view === 'recommend' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-800'}`}
            >
              <Sparkles size={16} />
              Recommend
            </button>
          </nav>
        )}
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-5xl mx-auto w-full px-6 py-8">
        {view === 'onboarding' && (
          <Onboarding 
            onItemsAdded={addItems} 
            wardrobe={wardrobe} 
            onComplete={finishOnboarding} 
          />
        )}

        {view === 'wardrobe' && (
          <WardrobeGrid 
            items={wardrobe} 
            onDelete={deleteItem} 
            onUpdate={updateItem}
            onAddMore={() => setView('onboarding')}
          />
        )}

        {view === 'recommend' && (
          <OutfitRecommender wardrobe={wardrobe} />
        )}
      </main>

      {/* Footer Branding */}
      <footer className="py-6 text-center text-slate-400 text-xs">
        &copy; 2024 StyleMind AI. Personal fashion made intelligent.
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ClothingItem, ClothingCategory } from '../types';
import { analyzeClothingImage } from '../services/geminiService';
import { Upload, Loader2, CheckCircle2, AlertCircle, Plus } from 'lucide-react';

interface OnboardingProps {
  onItemsAdded: (items: ClothingItem[]) => void;
  wardrobe: ClothingItem[];
  onComplete: () => void;
}

const Onboarding: React.FC<OnboardingProps> = ({ onItemsAdded, wardrobe, onComplete }) => {
  const [analyzing, setAnalyzing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const hasShirt = wardrobe.some(i => i.category === ClothingCategory.SHIRT);
  const hasPants = wardrobe.some(i => i.category === ClothingCategory.PANTS);
  const isReady = hasShirt && hasPants;

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setAnalyzing(true);
    setError(null);

    try {
      const newItems: ClothingItem[] = [];

      for (const file of Array.from(files)) {
        const base64 = await fileToBase64(file);
        const analysis = await analyzeClothingImage(base64);

        if (analysis.length === 0) {
          setError("Could not identify any clothes in this image. Please try another.");
          continue;
        }

        analysis.forEach((res, idx) => {
          newItems.push({
            id: Math.random().toString(36).substr(2, 9),
            image: base64,
            category: res.category || ClothingCategory.OTHER,
            color: res.color || 'Unknown',
            material: res.material || 'Unknown',
            pattern: res.pattern || 'Solid',
            style: res.style || 'Casual',
            season: res.season || 'All-season',
            description: res.description || 'No description provided.'
          });
        });
      }

      onItemsAdded(newItems);
    } catch (err) {
      setError("Something went wrong during analysis.");
      console.error(err);
    } finally {
      setAnalyzing(false);
    }
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  return (
    <div className="max-w-2xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="text-center space-y-4">
        <h2 className="text-3xl font-extrabold text-slate-900">Build Your Digital Closet</h2>
        <p className="text-slate-500">
          Upload photos of your clothes. You can upload one item at a time or a single photo with multiple items. 
          To start, we need at least one shirt and one pair of pants.
        </p>
      </div>

      {/* Progress Cards */}
      <div className="grid grid-cols-2 gap-4">
        <div className={`p-4 rounded-2xl border-2 transition-all ${hasShirt ? 'border-green-100 bg-green-50' : 'border-slate-100 bg-white'}`}>
          <div className="flex justify-between items-center mb-2">
            <span className={`text-sm font-semibold ${hasShirt ? 'text-green-700' : 'text-slate-400'}`}>SHIRT</span>
            {hasShirt ? <CheckCircle2 size={20} className="text-green-500" /> : <div className="w-5 h-5 rounded-full border-2 border-slate-200" />}
          </div>
          <p className="text-xs text-slate-400">Essential for recommendations</p>
        </div>
        <div className={`p-4 rounded-2xl border-2 transition-all ${hasPants ? 'border-green-100 bg-green-50' : 'border-slate-100 bg-white'}`}>
          <div className="flex justify-between items-center mb-2">
            <span className={`text-sm font-semibold ${hasPants ? 'text-green-700' : 'text-slate-400'}`}>PANTS</span>
            {hasPants ? <CheckCircle2 size={20} className="text-green-500" /> : <div className="w-5 h-5 rounded-full border-2 border-slate-200" />}
          </div>
          <p className="text-xs text-slate-400">Essential for recommendations</p>
        </div>
      </div>

      {/* Upload Zone */}
      <div className="relative group">
        <input 
          type="file" 
          multiple 
          accept="image/*" 
          onChange={handleFileUpload}
          disabled={analyzing}
          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
        />
        <div className={`border-2 border-dashed rounded-3xl p-12 text-center transition-all ${analyzing ? 'bg-slate-50 border-indigo-200' : 'border-slate-200 group-hover:border-indigo-400 group-hover:bg-indigo-50/30'}`}>
          <div className="mx-auto w-16 h-16 bg-indigo-100 rounded-2xl flex items-center justify-center text-indigo-600 mb-4 group-hover:scale-110 transition-transform">
            {analyzing ? <Loader2 size={32} className="animate-spin" /> : <Upload size={32} />}
          </div>
          <h3 className="text-lg font-semibold text-slate-800">
            {analyzing ? 'AI is scanning your wardrobe...' : 'Click or Drag to Upload'}
          </h3>
          <p className="text-sm text-slate-400 mt-2">
            PNG, JPG up to 10MB
          </p>
          {analyzing && (
            <div className="mt-4 flex items-center justify-center gap-2 text-indigo-500 text-sm font-medium">
              <span className="inline-block w-2 h-2 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
              <span className="inline-block w-2 h-2 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
              <span className="inline-block w-2 h-2 bg-indigo-500 rounded-full animate-bounce"></span>
            </div>
          )}
        </div>
      </div>

      {error && (
        <div className="bg-red-50 text-red-600 p-4 rounded-xl flex items-center gap-3 text-sm animate-in fade-in zoom-in-95">
          <AlertCircle size={18} />
          {error}
        </div>
      )}

      {/* Wardrobe Preview if items exist */}
      {wardrobe.length > 0 && (
        <div className="space-y-4">
          <h4 className="font-semibold text-slate-700">Recently Added ({wardrobe.length})</h4>
          <div className="flex gap-3 overflow-x-auto pb-4 scrollbar-hide">
            {wardrobe.map((item) => (
              <div key={item.id} className="min-w-[120px] w-[120px] h-[160px] rounded-xl overflow-hidden relative border border-slate-200 shadow-sm flex-shrink-0">
                <img src={item.image} alt={item.category} className="w-full h-full object-cover" />
                <div className="absolute bottom-0 inset-x-0 bg-gradient-to-t from-black/60 to-transparent p-2">
                  <span className="text-[10px] font-bold text-white uppercase">{item.category}</span>
                </div>
              </div>
            ))}
            <div className="min-w-[120px] w-[120px] h-[160px] border-2 border-dashed border-slate-200 rounded-xl flex items-center justify-center text-slate-300">
              <Plus size={24} />
            </div>
          </div>
        </div>
      )}

      {/* Action */}
      <button
        onClick={onComplete}
        disabled={!isReady || analyzing}
        className={`w-full py-4 rounded-2xl font-bold text-lg transition-all shadow-xl ${
          isReady && !analyzing 
          ? 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-200 active:scale-[0.98]' 
          : 'bg-slate-200 text-slate-400 cursor-not-allowed'
        }`}
      >
        {isReady ? 'Go to My Wardrobe' : 'Upload Shirt & Pants to Continue'}
      </button>
    </div>
  );
};

export default Onboarding;

import React, { useState } from 'react';
import { ClothingItem, ClothingCategory } from '../types';
import ItemCard from './ItemCard';
import { Filter, Search, PlusCircle } from 'lucide-react';

interface WardrobeGridProps {
  items: ClothingItem[];
  onDelete: (id: string) => void;
  onUpdate: (item: ClothingItem) => void;
  onAddMore: () => void;
}

const WardrobeGrid: React.FC<WardrobeGridProps> = ({ items, onDelete, onUpdate, onAddMore }) => {
  const [filter, setFilter] = useState<ClothingCategory | 'all'>('all');
  const [search, setSearch] = useState('');

  const filteredItems = items.filter(item => {
    const matchesFilter = filter === 'all' || item.category === filter;
    const matchesSearch = item.description.toLowerCase().includes(search.toLowerCase()) ||
                        item.color.toLowerCase().includes(search.toLowerCase()) ||
                        item.style.toLowerCase().includes(search.toLowerCase());
    return matchesFilter && matchesSearch;
  });

  const categories = ['all', ...Object.values(ClothingCategory)];

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <h2 className="text-2xl font-bold text-slate-800">My Wardrobe ({items.length})</h2>
        <button 
          onClick={onAddMore}
          className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-xl font-medium hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-100"
        >
          <PlusCircle size={18} />
          Add Item
        </button>
      </div>

      {/* Controls */}
      <div className="flex flex-col sm:flex-row gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
          <input 
            type="text" 
            placeholder="Search by color, style, material..." 
            className="w-full pl-10 pr-4 py-2.5 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none transition-all"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <div className="flex gap-2 overflow-x-auto pb-1 no-scrollbar">
          {categories.map((cat) => (
            <button
              key={cat}
              onClick={() => setFilter(cat as any)}
              className={`px-4 py-2 rounded-xl text-sm font-medium capitalize whitespace-nowrap transition-all ${
                filter === cat 
                ? 'bg-slate-800 text-white' 
                : 'bg-white text-slate-600 border border-slate-200 hover:border-slate-300'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      {/* Grid */}
      {filteredItems.length > 0 ? (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
          {filteredItems.map((item) => (
            <ItemCard 
              key={item.id} 
              item={item} 
              onDelete={onDelete} 
              onUpdate={onUpdate} 
            />
          ))}
        </div>
      ) : (
        <div className="text-center py-20 bg-white border border-dashed border-slate-200 rounded-3xl">
          <div className="mx-auto w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center text-slate-300 mb-4">
            <Filter size={32} />
          </div>
          <h3 className="text-slate-800 font-semibold text-lg">No items found</h3>
          <p className="text-slate-400 max-w-xs mx-auto mt-2">
            Try adjusting your search or filters to find what you're looking for.
          </p>
        </div>
      )}
    </div>
  );
};

export default WardrobeGrid;

import React, { useState } from 'react';
import { ClothingItem, ClothingCategory } from '../types';
import { Trash2, Edit3, Check, X, Tag, Palette, Box } from 'lucide-react';

interface ItemCardProps {
  item: ClothingItem;
  onDelete: (id: string) => void;
  onUpdate: (item: ClothingItem) => void;
}

const ItemCard: React.FC<ItemCardProps> = ({ item, onDelete, onUpdate }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editData, setEditData] = useState<ClothingItem>(item);

  const handleSave = () => {
    onUpdate(editData);
    setIsEditing(false);
  };

  const handleCancel = () => {
    setEditData(item);
    setIsEditing(false);
  };

  return (
    <div className="group bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all duration-300">
      {/* Image Container */}
      <div className="aspect-[3/4] overflow-hidden relative">
        <img 
          src={item.image} 
          alt={item.description} 
          className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
        />
        <div className="absolute top-3 left-3">
          <span className="px-3 py-1 bg-white/90 backdrop-blur-md text-[10px] font-bold uppercase rounded-full text-slate-800 shadow-sm border border-white/50">
            {item.category}
          </span>
        </div>
        <div className="absolute top-3 right-3 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
          <button 
            onClick={() => setIsEditing(true)}
            className="p-2 bg-indigo-600 text-white rounded-full hover:bg-indigo-700 shadow-lg"
          >
            <Edit3 size={14} />
          </button>
          <button 
            onClick={() => onDelete(item.id)}
            className="p-2 bg-rose-600 text-white rounded-full hover:bg-rose-700 shadow-lg"
          >
            <Trash2 size={14} />
          </button>
        </div>
      </div>

      {/* Info */}
      <div className="p-4 space-y-3">
        {isEditing ? (
          <div className="space-y-3">
             <div>
              <label className="text-[10px] font-bold text-slate-400 uppercase">Category</label>
              <select 
                value={editData.category}
                onChange={(e) => setEditData({...editData, category: e.target.value as ClothingCategory})}
                className="w-full text-sm border-b border-slate-200 py-1 outline-none"
              >
                {Object.values(ClothingCategory).map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="text-[10px] font-bold text-slate-400 uppercase">Description</label>
              <textarea 
                value={editData.description}
                onChange={(e) => setEditData({...editData, description: e.target.value})}
                className="w-full text-sm border-b border-slate-200 py-1 outline-none resize-none h-16"
              />
            </div>
            <div className="flex gap-2">
              <button onClick={handleSave} className="flex-1 bg-green-500 text-white p-2 rounded-lg"><Check size={16} className="mx-auto" /></button>
              <button onClick={handleCancel} className="flex-1 bg-slate-200 text-slate-600 p-2 rounded-lg"><X size={16} className="mx-auto" /></button>
            </div>
          </div>
        ) : (
          <>
            <p className="text-sm font-medium text-slate-800 line-clamp-2 min-h-[40px]">
              {item.description}
            </p>
            <div className="grid grid-cols-2 gap-2">
              <div className="flex items-center gap-2 text-slate-500">
                <Palette size={14} className="text-indigo-400" />
                <span className="text-xs truncate">{item.color}</span>
              </div>
              <div className="flex items-center gap-2 text-slate-500">
                <Tag size={14} className="text-indigo-400" />
                <span className="text-xs truncate">{item.style}</span>
              </div>
              <div className="flex items-center gap-2 text-slate-500">
                <Box size={14} className="text-indigo-400" />
                <span className="text-xs truncate">{item.material}</span>
              </div>
              <div className="flex items-center gap-2 text-slate-500">
                <span className="text-xs truncate font-semibold uppercase text-slate-400">{item.season}</span>
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default ItemCard;

import React, { useState } from 'react';
import { ClothingItem, RecommendedOutfit } from '../types';
import { getOutfitRecommendation } from '../services/geminiService';
import { Sparkles, Send, Loader2, Quote, ArrowRight } from 'lucide-react';

interface OutfitRecommenderProps {
  wardrobe: ClothingItem[];
}

const OutfitRecommender: React.FC<OutfitRecommenderProps> = ({ wardrobe }) => {
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [recommendation, setRecommendation] = useState<RecommendedOutfit | null>(null);

  const handleRecommend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!prompt.trim() || loading) return;

    setLoading(true);
    setRecommendation(null);

    try {
      const result = await getOutfitRecommendation(wardrobe, prompt);
