            </div>
            <h3 className="text-lg font-semibold text-slate-800">Choose Photos</h3>
            <p className="text-sm text-slate-400 mt-1">Select one or more images of your clothes</p>
          </div>
        </div>
      )}

      {/* Pending Queue */}
      {pendingUploads.length > 0 && (
        <div className="bg-white rounded-3xl p-6 border border-slate-100 shadow-sm space-y-4">
          <div className="flex justify-between items-center">
            <h4 className="font-bold text-slate-800 flex items-center gap-2">
              <ImageIcon size={18} className="text-slate-400" />
              Upload Queue ({pendingUploads.length})
            </h4>
            {!analyzing && (
              <button 
                onClick={processQueue}
                className="bg-indigo-600 text-white px-6 py-2 rounded-xl font-bold flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"
              >
                <Sparkles size={18} />
                Process All
              </button>
            )}
          </div>

          <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-5 gap-3">
            {pendingUploads.map((pending, idx) => (
              <div key={pending.id} className={`aspect-square rounded-xl overflow-hidden relative group border-2 ${analyzing && processingIndex === idx ? 'border-indigo-500 ring-2 ring-indigo-200' : 'border-slate-100'}`}>
                <img src={pending.base64} alt="Pending" className={`w-full h-full object-cover ${analyzing && processingIndex !== idx && processingIndex! > idx ? 'opacity-40 grayscale' : ''}`} />
                {!analyzing && (
                  <button 
                    onClick={() => removePending(pending.id)}
                    className="absolute top-1 right-1 p-1 bg-black/50 text-white rounded-full hover:bg-rose-600 transition-colors"
                  >
                    <X size={12} />
                  </button>
                )}
                {analyzing && processingIndex === idx && (
                  <div className="absolute inset-0 bg-indigo-600/20 backdrop-blur-[1px] flex items-center justify-center">
                    <Loader2 size={24} className="text-white animate-spin" />
                  </div>
                )}
              </div>
            ))}
          </div>

          {analyzing && (
            <div className="space-y-2">
              <div className="flex justify-between text-xs font-bold text-indigo-600 uppercase">
                <span>Analyzing your items...</span>
                <span>{processingIndex! + 1} / {pendingUploads.length}</span>
              </div>
              <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                <div 
                  className="bg-indigo-600 h-full transition-all duration-500" 
                  style={{ width: `${((processingIndex! + 1) / pendingUploads.length) * 100}%` }}
                />
              </div>
            </div>
          )}
        </div>
      )}

      {/* Wardrobe Preview (Processed Items) */}
      {wardrobe.length > 0 && (
        <div className="space-y-4">
          <h4 className="font-bold text-slate-800 flex items-center gap-2">
            <CheckCircle2 size={18} className="text-green-500" />
            Confirmed in Wardrobe ({wardrobe.length})
          </h4>
          <div className="flex gap-3 overflow-x-auto pb-4 no-scrollbar">
            {wardrobe.map((item) => (
              <div key={item.id} className="min-w-[100px] w-[100px] h-[130px] rounded-xl overflow-hidden relative border border-slate-200 shadow-sm flex-shrink-0 animate-in zoom-in duration-300">
                <img src={item.image} alt={item.category} className="w-full h-full object-cover" />
                <div className="absolute bottom-0 inset-x-0 bg-gradient-to-t from-black/80 to-transparent p-1.5">
                  <span className="text-[8px] font-bold text-white uppercase truncate block">{item.category}</span>
                  <span className="text-[8px] text-white/70 block truncate">{item.color}</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {error && (
        <div className="bg-rose-50 border border-rose-100 text-rose-600 p-4 rounded-2xl flex items-center gap-3 text-sm animate-in shake duration-300">
          <AlertCircle size={20} />
          <p className="font-medium">{error}</p>
        </div>
      )}

      {/* Final Action */}
      <div className="pt-4">
        <button
          onClick={onComplete}
          disabled={!isRequirementsMet || analyzing}
          className={`w-full py-4 rounded-2xl font-bold text-lg transition-all shadow-xl flex items-center justify-center gap-3 ${
            isRequirementsMet && !analyzing 
            ? 'bg-slate-900 text-white hover:bg-black active:scale-[0.98]' 
            : 'bg-slate-100 text-slate-300 cursor-not-allowed shadow-none'
          }`}
        >
          {isRequirementsMet ? (
            <>
              Explore Wardrobe
              <Sparkles size={20} className="text-yellow-400" />
            </>
          ) : (
            'Complete Setup to Continue'
          )}
        </button>
        {!isRequirementsMet && wardrobe.length > 0 && (
          <p className="text-center text-xs text-slate-400 mt-4">
            Almost there! Just need to identify at least one {!hasShirt ? 'Shirt' : ''} {!hasShirt && !hasPants ? 'and' : ''} {!hasPants ? 'Pant' : ''}.
          </p>
        )}
      </div>
    </div>
  );
};

export default Onboarding;

import React, { useState, useEffect } from 'react';
import { View, ClothingItem, ClothingCategory } from './types';
import Onboarding from './components/Onboarding';
import WardrobeGrid from './components/WardrobeGrid';
import OutfitRecommender from './components/OutfitRecommender';
import { Shirt, LayoutGrid, Sparkles, AlertCircle } from 'lucide-react';

const STORAGE_KEY = 'stylemind_wardrobe';

const App: React.FC = () => {
  const [view, setView] = useState<View>('onboarding');
  const [wardrobe, setWardrobe] = useState<ClothingItem[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Load wardrobe from localStorage
  useEffect(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        const items = JSON.parse(saved);
        setWardrobe(items);

        const hasShirt = items.some((i: ClothingItem) => i.category === ClothingCategory.SHIRT);
        const hasPants = items.some((i: ClothingItem) => i.category === ClothingCategory.PANTS);

        if (hasShirt && hasPants) {
          setView('wardrobe');
        }
      }
    } catch (e) {
      console.error("Failed to load wardrobe", e);
    }
  }, []);

  // Save wardrobe to localStorage with safety
  useEffect(() => {
    if (wardrobe.length === 0) return;
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(wardrobe));
    } catch (e) {
      console.error("Failed to save to localStorage (Quota likely exceeded)", e);
      setError("Storage full! Please delete some items or use smaller images.");
    }
  }, [wardrobe]);

  const addItems = (newItems: ClothingItem[]) => {
    setWardrobe(prev => [...prev, ...newItems]);
  };

  const deleteItem = (id: string) => {
    setWardrobe(prev => prev.filter(item => item.id !== id));
  };

  const updateItem = (updated: ClothingItem) => {
    setWardrobe(prev => prev.map(item => item.id === updated.id ? updated : item));
  };

  return (
    <div className="flex flex-col min-h-screen bg-slate-50">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-indigo-200">
            <Shirt size={24} />
          </div>
          <h1 className="text-xl font-bold tracking-tight text-slate-800">StyleMind</h1>
        </div>

        {view !== 'onboarding' && (
          <nav className="flex gap-1 bg-slate-100 p-1 rounded-lg">
            <button 
              onClick={() => setView('wardrobe')}
              className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-all ${view === 'wardrobe' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-800'}`}
            >
              <LayoutGrid size={16} />
              Wardrobe
            </button>
            <button 
              onClick={() => setView('recommend')}
              className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-all ${view === 'recommend' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-800'}`}
            >
              <Sparkles size={16} />
              Recommend
            </button>
          </nav>
        )}
      </header>

      {error && (
        <div className="bg-amber-50 border-b border-amber-100 px-6 py-2 flex items-center gap-2 text-amber-700 text-sm font-medium">
          <AlertCircle size={14} />
          {error}
          <button onClick={() => setError(null)} className="ml-auto underline">Dismiss</button>
        </div>
      )}

      {/* Main Content */}
      <main className="flex-1 max-w-5xl mx-auto w-full px-6 py-8">
        {view === 'onboarding' && (
          <Onboarding 
            onItemsAdded={addItems} 
            wardrobe={wardrobe} 
            onComplete={() => setView('wardrobe')} 
          />
        )}

        {view === 'wardrobe' && (
          <WardrobeGrid 
            items={wardrobe} 
            onDelete={deleteItem} 
            onUpdate={updateItem}
            onAddMore={() => setView('onboarding')}
          />
