        {view === 'recommend' && (
          <OutfitRecommender wardrobe={wardrobe} />
        )}
      </main>

      {/* Footer Branding */}
      <footer className="py-6 text-center text-slate-400 text-xs">
        &copy; 2024 StyleMind AI. Personal fashion made intelligent.
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { ClothingItem, ClothingCategory } from '../types';
import { analyzeClothingImage } from '../services/geminiService';
import { Upload, Loader2, CheckCircle2, AlertCircle, X, Sparkles, Image as ImageIcon, Plus } from 'lucide-react';

interface OnboardingProps {
  onItemsAdded: (items: ClothingItem[]) => void;
  wardrobe: ClothingItem[];
  onComplete: () => void;
}

interface PendingUpload {
  id: string;
  base64: string;
}

const Onboarding: React.FC<OnboardingProps> = ({ onItemsAdded, wardrobe, onComplete }) => {
  const [pendingQueue, setPendingQueue] = useState<PendingUpload[]>([]);
  const [analyzing, setAnalyzing] = useState(false);
  const [processingIndex, setProcessingIndex] = useState<number | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const hasShirt = wardrobe.some(i => i.category === ClothingCategory.SHIRT);
  const hasPants = wardrobe.some(i => i.category === ClothingCategory.PANTS);
  const isRequirementsMet = hasShirt && hasPants;

  // Utility to compress image to prevent LocalStorage Quota crashes
  const compressImage = (file: File): Promise<string> => {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const MAX_SIZE = 800;
          let width = img.width;
          let height = img.height;

          if (width > height) {
            if (width > MAX_SIZE) {
              height *= MAX_SIZE / width;
              width = MAX_SIZE;
            }
          } else {
            if (height > MAX_SIZE) {
              width *= MAX_SIZE / height;
              height = MAX_SIZE;
            }
          }

          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');
          ctx?.drawImage(img, 0, 0, width, height);
          // Use a medium quality for good balance between AI clarity and storage size
          resolve(canvas.toDataURL('image/jpeg', 0.7));
        };
      };
    });
  };

  const handleFileSelection = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setError(null);
    const newPending: PendingUpload[] = [];
    const fileList = Array.from(files);

    for (const file of fileList) {
      try {
        const compressedBase64 = await compressImage(file);
        newPending.push({
          id: Math.random().toString(36).substr(2, 9),
          base64: compressedBase64
        });
      } catch (err) {
        console.error("Error reading file", err);
        setError("One or more images could not be loaded.");
      }
    }

    setPendingQueue(prev => [...prev, ...newPending]);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removePending = (id: string) => {
    setPendingQueue(prev => prev.filter(p => p.id !== id));
  };

  const startBatchProcessing = async () => {
    if (pendingQueue.length === 0) {
      if (isRequirementsMet) onComplete();
      return;
    }

    setAnalyzing(true);
    setError(null);
    const successfullyProcessed: ClothingItem[] = [];

    for (let i = 0; i < pendingQueue.length; i++) {
      setProcessingIndex(i);
      const pending = pendingQueue[i];

      try {
        const analysis = await analyzeClothingImage(pending.base64);

        if (analysis && analysis.length > 0) {
          analysis.forEach((res) => {
            successfullyProcessed.push({
              id: Math.random().toString(36).substr(2, 9),
              image: pending.base64,
              category: (res.category as ClothingCategory) || ClothingCategory.OTHER,
              color: res.color || 'Unknown',
              material: res.material || 'Unknown',
              pattern: res.pattern || 'Solid',
              style: res.style || 'Casual',
              season: res.season || 'All-season',
              description: res.description || 'No description provided.'
            });
          });
        }
      } catch (err) {
        console.error(`Error processing image ${i + 1}`, err);
        setError(`Processing failed at item ${i + 1}. We'll save what we found so far.`);
      }
    }

    if (successfullyProcessed.length > 0) {
      onItemsAdded(successfullyProcessed);
      setPendingQueue([]);

      // Auto-complete if requirements are met after this batch
      const updatedWardrobe = [...wardrobe, ...successfullyProcessed];
      const metNow = updatedWardrobe.some(i => i.category === ClothingCategory.SHIRT) && 
                     updatedWardrobe.some(i => i.category === ClothingCategory.PANTS);

      if (metNow) {
        onComplete();
      }
    } else {
      setError("No clothes were detected. Please try clearer images.");
    }

    setAnalyzing(false);
    setProcessingIndex(null);
  };

  return (
    <div className="max-w-3xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700 pb-20">
      <div className="text-center space-y-4">
        <h2 className="text-3xl font-extrabold text-slate-900">Digitalize Your Closet</h2>
        <p className="text-slate-500">
          Upload photos of your clothes. Once you're done, we'll use AI to organize them into your profile.
        </p>
      </div>

      {/* Requirement Tracker */}
      <div className="grid grid-cols-2 gap-4">
        <div className={`p-4 rounded-2xl border-2 flex items-center justify-between transition-all ${hasShirt ? 'border-green-100 bg-green-50' : 'border-slate-100 bg-white'}`}>
          <div className="flex flex-col">
            <span className={`text-sm font-bold ${hasShirt ? 'text-green-700' : 'text-slate-400'}`}>SHIRT</span>
            <span className="text-[10px] text-slate-400 uppercase">{hasShirt ? 'Completed' : 'Missing'}</span>
          </div>
          {hasShirt ? <CheckCircle2 size={24} className="text-green-500" /> : <div className="w-6 h-6 rounded-full border-2 border-slate-200" />}
        </div>
        <div className={`p-4 rounded-2xl border-2 flex items-center justify-between transition-all ${hasPants ? 'border-green-100 bg-green-50' : 'border-slate-100 bg-white'}`}>
          <div className="flex flex-col">
            <span className={`text-sm font-bold ${hasPants ? 'text-green-700' : 'text-slate-400'}`}>PANTS</span>
            <span className="text-[10px] text-slate-400 uppercase">{hasPants ? 'Completed' : 'Missing'}</span>
          </div>
          {hasPants ? <CheckCircle2 size={24} className="text-green-500" /> : <div className="w-6 h-6 rounded-full border-2 border-slate-200" />}
        </div>
      </div>

      {/* Upload Box */}
      {!analyzing && (
        <div className="relative group">
          <input 
            type="file" 
            multiple 
            ref={fileInputRef}
            accept="image/*" 
            onChange={handleFileSelection}
            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
          />
          <div className="border-2 border-dashed border-slate-200 rounded-3xl p-10 text-center transition-all group-hover:border-indigo-400 group-hover:bg-indigo-50/30">
            <div className="mx-auto w-14 h-14 bg-indigo-100 rounded-2xl flex items-center justify-center text-indigo-600 mb-4 group-hover:scale-110 transition-transform">
              <Plus size={28} />
            </div>
            <h3 className="text-lg font-semibold text-slate-800">Add Clothes</h3>
            <p className="text-sm text-slate-400 mt-1">Single or multiple items per photo</p>
          </div>
        </div>
      )}

      {/* Pending Items Display */}
      {pendingQueue.length > 0 && (
        <div className="bg-white rounded-3xl p-6 border border-slate-100 shadow-sm space-y-4">
          <h4 className="font-bold text-slate-800 flex items-center gap-2">
            <ImageIcon size={18} className="text-slate-400" />
            Selected for Processing ({pendingQueue.length})
          </h4>

          <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-5 gap-3">
            {pendingQueue.map((pending, idx) => (
              <div key={pending.id} className={`aspect-square rounded-xl overflow-hidden relative border-2 ${analyzing && processingIndex === idx ? 'border-indigo-500 ring-2 ring-indigo-200' : 'border-slate-100'}`}>
                <img src={pending.base64} alt="Pending" className={`w-full h-full object-cover ${analyzing && processingIndex !== idx ? 'opacity-50' : ''}`} />
                {!analyzing && (
                  <button 
                    onClick={() => removePending(pending.id)}
                    className="absolute top-1 right-1 p-1 bg-black/60 text-white rounded-full hover:bg-rose-600 transition-colors"
                  >
                    <X size={12} />
                  </button>
                )}
                {analyzing && processingIndex === idx && (
                  <div className="absolute inset-0 bg-indigo-600/20 backdrop-blur-[1px] flex items-center justify-center">
                    <Loader2 size={24} className="text-white animate-spin" />
                  </div>
                )}
              </div>
            ))}
          </div>

          {analyzing && (
            <div className="pt-2">
              <div className="flex justify-between text-[10px] font-bold text-indigo-600 uppercase mb-1">
                <span>AI is analyzing item {processingIndex! + 1}...</span>
                <span>{Math.round(((processingIndex! + 1) / pendingQueue.length) * 100)}%</span>
              </div>
              <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                <div 
                  className="bg-indigo-600 h-full transition-all duration-500" 
                  style={{ width: `${((processingIndex! + 1) / pendingQueue.length) * 100}%` }}
                />
              </div>
            </div>
          )}
        </div>
      )}

      {error && (
        <div className="bg-rose-50 border border-rose-100 text-rose-600 p-4 rounded-2xl flex items-center gap-3 text-sm">
          <AlertCircle size={20} />
          <p className="font-medium">{error}</p>
        </div>
      )}

      {/* Primary Action Button */}
      <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-full max-w-lg px-6">
        <button
          onClick={startBatchProcessing}
          disabled={analyzing || (pendingQueue.length === 0 && !isRequirementsMet)}
          className={`w-full py-4 rounded-2xl font-bold text-lg transition-all shadow-2xl flex items-center justify-center gap-3 active:scale-[0.98] ${
            analyzing 
            ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
            : pendingQueue.length > 0 
              ? 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-200' 
              : isRequirementsMet 
                ? 'bg-slate-900 text-white'
                : 'bg-slate-100 text-slate-300 cursor-not-allowed'
          }`}
        >
          {analyzing ? (
            <>
              <Loader2 size={20} className="animate-spin" />
              Processing...
            </>
          ) : pendingQueue.length > 0 ? (
            <>
              Process {pendingQueue.length} {pendingQueue.length === 1 ? 'Item' : 'Items'}
              <Sparkles size={20} />
            </>
          ) : isRequirementsMet ? (
            'Continue to Wardrobe'
          ) : (
            'Add more items to continue'
          )}
        </button>
      </div>
    </div>
  );
};

export default Onboarding;

import { GoogleGenAI, Type } from "@google/genai";
import { ClothingItem, ClothingCategory } from "../types";

export const analyzeClothingImage = async (base64Image: string): Promise<any[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const prompt = `Analyze this image and identify all distinct clothing items present (e.g., if there are 3 shirts, identify each one separately).
  For each item found, provide details and its specific location in the image.

  Format the response as a JSON array of objects. Each object MUST have:
  - category: one of 'shirt', 'pants', 'accessory', 'shoes', 'other'
  - color: primary color
  - material: likely material
  - pattern: e.g., solid, striped, plaid, etc.
  - style: casual, formal, sporty, business-casual, etc.
  - season: spring, summer, fall, winter, or all-season
  - description: a concise 1-sentence description focusing on the unique look of this specific item.
  - box_2d: [ymin, xmin, ymax, xmax] coordinates (normalized 0-1000) for the bounding box containing ONLY this item.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image.split(',')[1] || base64Image } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              category: { type: Type.STRING, enum: Object.values(ClothingCategory) },
              color: { type: Type.STRING },
              material: { type: Type.STRING },
              pattern: { type: Type.STRING },
              style: { type: Type.STRING },
              season: { type: Type.STRING },
              description: { type: Type.STRING },
              box_2d: { 
                type: Type.ARRAY, 
                items: { type: Type.INTEGER },
                description: "Bounding box coordinates [ymin, xmin, ymax, xmax] from 0-1000"
              }
            },
            required: ["category", "color", "description", "box_2d"]
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];
    const data = JSON.parse(text);
    return Array.isArray(data) ? data : [];
  } catch (e) {
    console.error("Failed to analyze image with Gemini", e);
    return [];
  }
};

export const getOutfitRecommendation = async (
  wardrobe: ClothingItem[],
  userPrompt: string
): Promise<{ itemIds: string[]; explanation: string } | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const prompt = `You are a high-end fashion stylist with a keen eye for "vibe" and personal aesthetic.
  Based on the user's wardrobe and their specific request, recommend a cohesive outfit.

  WARDROBE:
