              id: Math.random().toString(36).substr(2, 9),
              image: croppedBase64,
              category: (res.category as ClothingCategory) || ClothingCategory.OTHER,
              color: res.color || 'Unknown',
              material: res.material || 'Unknown',
              pattern: res.pattern || 'Solid',
              style: res.style || 'Casual',
              season: res.season || 'All-season',
              description: res.description || 'No description provided.'
            });
          }
        }
      } catch (err) {
        console.error(`Error processing image ${i + 1}`, err);
        setError(`AI encountered an issue extracting items. We'll save what we can.`);
      }
    }

    if (successfullyProcessed.length > 0) {
      onItemsAdded(successfullyProcessed);
      setPendingQueue([]);
      const updatedWardrobe = [...wardrobe, ...successfullyProcessed];
      if (updatedWardrobe.some(i => i.category === ClothingCategory.SHIRT) && 
          updatedWardrobe.some(i => i.category === ClothingCategory.PANTS)) {
        onComplete();
      }
    } else {
      setError("No clothes were detected. Try a clear photo with good lighting.");
    }
    setAnalyzing(false);
    setProcessingIndex(null);
  };

  return (
    <div className="max-w-3xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700 pb-28">
      <div className="text-center space-y-4">
        <div className="inline-flex items-center gap-2 px-3 py-1 bg-indigo-50 text-indigo-600 rounded-full text-xs font-bold uppercase tracking-wider">
          <Scissors size={14} /> AI-Powered Extraction
        </div>
        <h2 className="text-4xl font-black text-slate-900 tracking-tight">Expand Your Closet</h2>
        <p className="text-slate-500 text-lg">
          Upload a photo with one or many items. Our AI will precisely cut out each piece and label it for you.
        </p>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className={`p-5 rounded-3xl border-2 flex items-center justify-between transition-all ${hasShirt ? 'border-green-200 bg-green-50 shadow-sm shadow-green-100' : 'border-slate-100 bg-white'}`}>
          <div className="flex flex-col">
            <span className={`text-sm font-black ${hasShirt ? 'text-green-700' : 'text-slate-400'}`}>SHIRTS</span>
            <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{hasShirt ? 'Unlocked' : 'Locked'}</span>
          </div>
          {hasShirt ? <CheckCircle2 size={28} className="text-green-500" /> : <div className="w-7 h-7 rounded-full border-2 border-slate-200" />}
        </div>
        <div className={`p-5 rounded-3xl border-2 flex items-center justify-between transition-all ${hasPants ? 'border-green-200 bg-green-50 shadow-sm shadow-green-100' : 'border-slate-100 bg-white'}`}>
          <div className="flex flex-col">
            <span className={`text-sm font-black ${hasPants ? 'text-green-700' : 'text-slate-400'}`}>PANTS</span>
            <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{hasPants ? 'Unlocked' : 'Locked'}</span>
          </div>
          {hasPants ? <CheckCircle2 size={28} className="text-green-500" /> : <div className="w-7 h-7 rounded-full border-2 border-slate-200" />}
        </div>
      </div>

      {!analyzing && (
        <div className="relative group">
          <input type="file" multiple ref={fileInputRef} accept="image/*" onChange={handleFileSelection} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10" />
          <div className="border-4 border-dashed border-slate-200 rounded-[2.5rem] p-16 text-center transition-all group-hover:border-indigo-400 group-hover:bg-indigo-50/20 group-hover:scale-[1.01]">
            <div className="mx-auto w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center text-white mb-6 shadow-xl shadow-indigo-200 group-hover:rotate-6 transition-transform">
              <Plus size={40} />
            </div>
            <h3 className="text-2xl font-bold text-slate-800 tracking-tight">Drop your photos here</h3>
            <p className="text-slate-400 mt-2 font-medium">Multiple items in one image is totally fine!</p>
          </div>
        </div>
      )}

      {pendingQueue.length > 0 && (
        <div className="bg-white rounded-[2.5rem] p-8 border border-slate-100 shadow-xl shadow-slate-200/50 space-y-6">
          <div className="flex justify-between items-center">
            <h4 className="text-lg font-black text-slate-800 flex items-center gap-3">
              <ImageIcon size={24} className="text-indigo-500" />
              Extraction Queue ({pendingQueue.length})
            </h4>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
            {pendingQueue.map((pending, idx) => (
              <div key={pending.id} className={`aspect-[3/4] rounded-3xl overflow-hidden relative border-4 transition-all ${analyzing && processingIndex === idx ? 'border-indigo-500 scale-105 shadow-2xl' : 'border-slate-50'}`}>
                <img src={pending.base64} alt="Pending" className={`w-full h-full object-cover ${analyzing && processingIndex !== idx ? 'opacity-30 grayscale' : ''}`} />
