                  <button onClick={() => removePending(pending.id)} className="absolute top-2 right-2 p-2 bg-white/90 text-rose-600 rounded-full hover:bg-rose-600 hover:text-white shadow-lg transition-all">
                    <X size={16} />
                  </button>
                )}
