                <span>AI Scissorhands at work...</span>
                <span>{Math.round(((processingIndex! + 1) / pendingQueue.length) * 100)}%</span>
              </div>
              <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden">
                <div className="bg-gradient-to-r from-indigo-500 to-indigo-700 h-full transition-all duration-700 ease-out" style={{ width: `${((processingIndex! + 1) / pendingQueue.length) * 100}%` }} />
              </div>
            </div>
          )}
        </div>
      )}

      {error && (
        <div className="bg-rose-50 border-2 border-rose-100 text-rose-600 p-6 rounded-[2rem] flex items-center gap-4 animate-in slide-in-from-top-2">
          <div className="w-12 h-12 bg-rose-100 rounded-2xl flex items-center justify-center flex-shrink-0">
            <AlertCircle size={24} />
          </div>
          <p className="font-bold">{error}</p>
        </div>
      )}

      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 w-full max-w-lg px-6 z-50">
        <button
          onClick={startBatchProcessing}
          disabled={analyzing || (pendingQueue.length === 0 && !isRequirementsMet)}
          className={`w-full py-5 rounded-[2rem] font-black text-xl transition-all shadow-2xl flex items-center justify-center gap-4 active:scale-95 ${
            analyzing 
            ? 'bg-slate-200 text-slate-400 cursor-not-allowed shadow-none' 
            : pendingQueue.length > 0 
              ? 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-300 ring-4 ring-indigo-50' 
              : isRequirementsMet 
                ? 'bg-slate-900 text-white hover:bg-black'
                : 'bg-slate-100 text-slate-300 cursor-not-allowed shadow-none'
          }`}
        >
          {analyzing ? (
            <>
              <Loader2 size={24} className="animate-spin" />
              Cutting out items...
            </>
          ) : pendingQueue.length > 0 ? (
            <>
              Extract {pendingQueue.length} {pendingQueue.length === 1 ? 'Item' : 'Items'}
              <Sparkles size={24} className="text-yellow-400" />
            </>
          ) : isRequirementsMet ? (
            'Enter Wardrobe'
          ) : (
            'Select items to extract'
          )}
        </button>
      </div>
    </div>
  );
};

