import { GoogleGenAI, Type } from "@google/genai";
import { ClothingItem, ClothingCategory } from "../types";

export const analyzeClothingImage = async (base64Image: string): Promise<any[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const prompt = `Analyze this image and identify all distinct clothing items present.
  Format the response as a JSON array of objects. Each object MUST have:
  - name: Unique, catchy name (e.g., "The Midnight Denim").
  - category: one of 'shirt', 'pants', 'accessory', 'shoes', 'other'
  - silhouette: 'tee', 'polo', 'hoodie', 'dress-shirt', 'tank', 'jeans', 'chinos', 'shorts', 'joggers', 'skirt', 'sneakers', 'boots', 'formal', 'sandals', 'watch', 'glasses', 'hat', 'scarf'
  - color: primary color name
  - hexColor: Valid CSS Hex Code (e.g., #2D3E50).
  - material: likely material
  - pattern: e.g., solid, striped, etc.
  - style: casual, formal, etc.
  - season: spring, summer, fall, winter, or all-season
  - description: 1-sentence description.
  - box_2d: [ymin, xmin, ymax, xmax] coordinates (normalized 0-1000).`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image.split(',')[1] || base64Image } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              category: { type: Type.STRING, enum: Object.values(ClothingCategory) },
              silhouette: { type: Type.STRING },
              color: { type: Type.STRING },
              hexColor: { type: Type.STRING },
              material: { type: Type.STRING },
              pattern: { type: Type.STRING },
              style: { type: Type.STRING },
              season: { type: Type.STRING },
              description: { type: Type.STRING },
              box_2d: { type: Type.ARRAY, items: { type: Type.INTEGER } }
            },
            required: ["name", "category", "silhouette", "hexColor", "box_2d"]
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];
    const data = JSON.parse(text);
    return Array.isArray(data) ? data : [];
  } catch (e) {
    console.error("Failed to analyze image", e);
    return [];
  }
};

export const getOutfitRecommendation = async (
  wardrobe: ClothingItem[],
  userPrompt: string,
  language: string = 'en'
): Promise<{ itemIds: string[]; explanation: string } | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const langMap: Record<string, string> = {
    'en': 'English', 'es': 'Spanish', 'fr': 'French', 'hi': 'Hindi', 'ja': 'Japanese'
  };

  const prompt = `You are a stylish best friend giving simple advice in ${langMap[language] || 'English'}.

  WARDROBE:
  ${JSON.stringify(wardrobe.map(item => ({ id: item.id, name: item.name, category: item.category, color: item.color, style: item.style, wearCount: item.wearCount })))}

  USER REQUEST:
  "${userPrompt}"

  Select 2-4 items. Refer to them by name. Explain why they work together.
  Return a JSON object with:
  - itemIds: IDs of selected items.
  - explanation: Short, simple, friendly explanation.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            itemIds: { type: Type.ARRAY, items: { type: Type.STRING } },
            explanation: { type: Type.STRING }
          },
          required: ["itemIds", "explanation"]
        }
      }
    });
    return response.text ? JSON.parse(response.text) : null;
  } catch (e) {
    return null;
  }
};

export const getShoppingSuggestions = async (
  wardrobe: ClothingItem[],
  location: string | null,
  language: string = 'en'
) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const favorites = [...wardrobe].sort((a, b) => b.wearCount - a.wearCount).slice(0, 3);
  const styleSummary = wardrobe.map(i => `${i.color} ${i.style} ${i.category}`).join(', ');

  const prompt = `You are the "Costume Designer", a friendly fashion buyer. 
  The user's favorite items are: ${favorites.map(f => f.name).join(', ')}. 
  Overall style: ${styleSummary}. 
  Location: ${location || 'Unknown'}.

  1. Use Google Search to find 3 REAL, shoppable clothing items that would perfectly complement their favorites and match current local trends in ${location || 'the world'}.
  2. For each item, you MUST include a specific purchase link and estimated price.
  3. Write a friendly message in ${language} explaining why these were picked based on what they already wear a lot.

  BE CONCISE. DO NOT USE JARGON.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      }
    });

    return {
      text: response.text,
      links: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => chunk.web) || []
    };
  } catch (e) {
    console.error("Failed to get shopping suggestions", e);
    return null;
  }
};

