const translations = {
  en: { 
    title: 'Chat with StyleMind', subtitle: 'Your personal stylish best friend.', placeholder: 'Where are you going today?',
    tips: 'Vibe ideas:', loading: 'Thinking...', resultTitle: 'Stylist Suggestion', empty: 'Ask me for a look!', worn: 'Mark as Worn', wearing: 'Wearing this!'
