const OutfitRecommender: React.FC<OutfitRecommenderProps> = ({ wardrobe, language, onMarkAsWorn }) => {
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [recommendation, setRecommendation] = useState<RecommendedOutfit | null>(null);
  const [hasMarked, setHasMarked] = useState(false);

  const t = translations[language] || translations['en'];

  const handleRecommend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!prompt.trim() || loading) return;
    setLoading(true);
    setRecommendation(null);
    setHasMarked(false);
    try {
      const result = await getOutfitRecommendation(wardrobe, prompt, language);
      if (result) {
        const selectedItems = result.itemIds
          .map(id => wardrobe.find(item => item.id === id))
          .filter(item => !!item) as ClothingItem[];
        setRecommendation({ items: selectedItems, explanation: result.explanation });
      }
    } catch (err) { console.error(err); } finally { setLoading(false); }
  };

  const handleWorn = () => {
    if (!recommendation) return;
    onMarkAsWorn(recommendation.items.map(i => i.id), prompt);
    setHasMarked(true);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-16 animate-in fade-in duration-1000 pb-32 px-4">
      <div className="text-center space-y-6">
