      <div className="bg-white p-12 rounded-[4rem] shadow-2xl shadow-slate-200 border border-slate-50">
        <form onSubmit={handleRecommend} className="flex flex-col sm:flex-row gap-6">
          <div className="relative flex-1">
            <UserCircle2 className="absolute left-8 top-1/2 -translate-y-1/2 text-indigo-500" size={32} />
            <input 
              type="text" placeholder={t.placeholder} 
              className="w-full pl-20 pr-8 py-8 bg-slate-50 border-none rounded-[2.5rem] focus:ring-8 focus:ring-indigo-500/10 outline-none text-2xl font-bold transition-all placeholder:text-slate-300"
              value={prompt} onChange={(e) => setPrompt(e.target.value)} disabled={loading}
            />
          </div>
          <button type="submit" disabled={!prompt.trim() || loading}
            className={`px-12 py-8 rounded-[2.5rem] font-black text-2xl flex items-center justify-center gap-4 transition-all active:scale-95 ${
              prompt.trim() && !loading ? 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-2xl' : 'bg-slate-100 text-slate-300'
            }`}
          >
            {loading ? <Loader2 size={40} className="animate-spin" /> : <ArrowRight size={40} />}
          </button>
        </form>
      </div>

      {loading && (
        <div className="py-32 text-center space-y-8 animate-pulse">
          <div className="inline-flex items-center justify-center w-32 h-32 bg-indigo-50 text-indigo-600 rounded-[3.5rem]">
            <Sparkles size={64} className="animate-spin" />
          </div>
          <p className="text-slate-500 font-black text-3xl tracking-tight">{t.loading}</p>
        </div>
      )}

      {recommendation && !loading && (
        <div className="space-y-12 animate-in slide-in-from-bottom-12 duration-1000">
          <div className="bg-white p-12 rounded-[4.5rem] shadow-2xl shadow-indigo-50 border-8 border-indigo-50/50 space-y-12">
            <div className="flex items-start gap-8">
              <div className="p-6 bg-indigo-600 text-white rounded-[2rem] shadow-2xl shadow-indigo-200">
                <Quote size={40} />
              </div>
              <div className="flex-1 pt-4">
                <h3 className="text-3xl font-black text-slate-900 mb-6">{t.resultTitle}</h3>
                <p className="text-3xl text-slate-700 font-medium leading-[1.6] tracking-tight">{recommendation.explanation}</p>
                <div className="mt-8">
                  <button 
                    onClick={handleWorn}
                    disabled={hasMarked}
                    className={`flex items-center gap-3 px-8 py-4 rounded-2xl font-black transition-all ${
                      hasMarked ? 'bg-green-100 text-green-700' : 'bg-slate-900 text-white hover:bg-black active:scale-95 shadow-xl'
                    }`}
                  >
                    {hasMarked ? <CheckCircle size={20} /> : null}
                    {hasMarked ? t.wearing : t.worn}
                  </button>
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-10 pt-12 border-t-4 border-slate-50">
              {recommendation.items.map((item) => (
                <div key={item.id} className="space-y-6 group">
                  <div className="aspect-[4/5] rounded-[3.5rem] overflow-hidden bg-slate-50 border-2 border-slate-50 shadow-sm flex items-center justify-center p-10">
                    <div className="w-full h-full relative">
                      <div className="absolute inset-0 rounded-full opacity-10 blur-[40px]" style={{ backgroundColor: item.hexColor }} />
                      <svg viewBox="0 0 24 24" className="w-full h-full drop-shadow-xl">
                        <path fill={item.hexColor} d="M12 4L16 6V10H14V20H10V10H8V6L12 4Z" />
                      </svg>
                    </div>
                  </div>
                  <div className="px-4 text-center">
                    <h5 className="text-xl font-black text-slate-900 leading-tight">{item.name}</h5>
                    <p className="text-xs font-black text-indigo-500 uppercase tracking-widest mt-2">{item.category}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

