import React, { useState, useRef, useEffect } from 'react';
import { ClothingItem, Language, ChatMessage } from '../types';
import { getChatStylistResponse } from '../services/geminiService';
import { Sparkles, Loader2, Send, User, Bot, CheckCircle, Quote } from 'lucide-react';

interface OutfitRecommenderProps {
  wardrobe: ClothingItem[];
  language: Language;
  chatHistory: ChatMessage[];
  setChatHistory: React.Dispatch<React.SetStateAction<ChatMessage[]>>;
  onMarkAsWorn: (itemIds: string[]) => void;
}

const OutfitRecommender: React.FC<OutfitRecommenderProps> = ({ wardrobe, language, chatHistory, setChatHistory, onMarkAsWorn }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory, loading]);

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: new Date().toISOString()
    };

    setChatHistory(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    const response = await getChatStylistResponse(wardrobe, chatHistory, input, language);
    if (response) {
      const modelMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response.text,
        itemIds: response.itemIds,
        timestamp: new Date().toISOString()
      };
      setChatHistory(prev => [...prev, modelMsg]);
    }
    setLoading(false);
  };

  const clearHistory = () => {
    if (confirm("Clear chat history?")) setChatHistory([]);
  };

  return (
    <div className="max-w-4xl mx-auto h-[75vh] flex flex-col bg-white rounded-[3rem] shadow-2xl overflow-hidden border border-slate-100">
      {/* Chat Header */}
      <div className="bg-white border-b border-slate-50 p-6 flex justify-between items-center">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white">
            <Sparkles size={20} />
          </div>
          <div>
            <h3 className="font-black text-slate-900">Style Consultant</h3>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Powered by Gemini 3</p>
          </div>
        </div>
        <button onClick={clearHistory} className="text-[10px] font-black text-slate-300 hover:text-rose-500 uppercase tracking-widest transition-colors">Clear Chat</button>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-8 space-y-8 no-scrollbar">
        {chatHistory.length === 0 && !loading && (
          <div className="h-full flex flex-col items-center justify-center text-center space-y-6 opacity-40">
            <Bot size={64} className="text-slate-200" />
            <p className="text-xl font-bold text-slate-400">Ask me anything about your closet.<br/>"What should I wear to a dinner?"</p>
          </div>
        )}

        {chatHistory.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
            <div className={`max-w-[85%] flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-10 h-10 rounded-2xl flex-shrink-0 flex items-center justify-center shadow-md ${msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-indigo-600'}`}>
                {msg.role === 'user' ? <User size={18} /> : <Bot size={18} />}
              </div>
              <div className="space-y-4">
                <div className={`p-6 rounded-[2rem] text-lg font-medium leading-relaxed shadow-sm ${msg.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-slate-50 text-slate-800 rounded-tl-none'}`}>
                  {msg.text}
                </div>

                {/* Embedded Outfit Suggestions */}
                {msg.itemIds && msg.itemIds.length > 0 && (
                  <div className="bg-indigo-50/50 p-6 rounded-[2.5rem] border-2 border-indigo-100 space-y-4">
                    <div className="flex items-center justify-between">
                       <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Recommended Look</span>
                       <button 
                         onClick={() => onMarkAsWorn(msg.itemIds!)}
                         className="flex items-center gap-2 px-3 py-1.5 bg-indigo-600 text-white text-[10px] font-black uppercase rounded-lg shadow-lg active:scale-90"
                       >
                         <CheckCircle size={12} /> Log Outfit
                       </button>
                    </div>
                    <div className="flex gap-4 overflow-x-auto pb-2 no-scrollbar">
                      {msg.itemIds.map(id => {
                        const item = wardrobe.find(i => i.id === id);
                        if (!item) return null;
                        return (
                          <div key={id} className="flex-shrink-0 w-24 space-y-2">
                            <div className="aspect-[4/5] bg-white rounded-2xl flex items-center justify-center p-4 border border-indigo-50">
                              <svg viewBox="0 0 24 24" className="w-full h-full drop-shadow-md">
                                <path fill={item.hexColor} d="M12 4L16 6V10H14V20H10V10H8V6L12 4Z" />
                              </svg>
                            </div>
                            <p className="text-[10px] font-bold text-center text-slate-600 truncate">{item.name}</p>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}

        {loading && (
          <div className="flex justify-start animate-pulse">
            <div className="flex gap-4">
              <div className="w-10 h-10 rounded-2xl bg-slate-100 flex items-center justify-center text-indigo-400">
                <Loader2 size={18} className="animate-spin" />
              </div>
              <div className="p-6 bg-slate-50 rounded-[2rem] rounded-tl-none text-slate-300 font-bold">Designing your look...</div>
            </div>
          </div>
        )}
        <div ref={scrollRef} />
      </div>

      {/* Input Area */}
      <form onSubmit={handleSend} className="p-6 bg-slate-50 border-t border-slate-100 flex gap-4 items-center">
        <input 
          type="text" 
          value={input} 
          onChange={(e) => setInput(e.target.value)}
