        <button 
          type="submit" 
          disabled={!input.trim() || loading}
          className={`w-14 h-14 rounded-full flex items-center justify-center transition-all active:scale-90 shadow-xl ${input.trim() && !loading ? 'bg-indigo-600 text-white hover:bg-indigo-700' : 'bg-slate-200 text-slate-400'}`}
        >
          <Send size={24} />
        </button>
      </form>
    </div>
  );
