  cache: DesignerState | null;
  setCache: (state: DesignerState) => void;
}

const SilhouetteIcon = ({ silhouette, color }: { silhouette: string, color: string }) => {
  const common = { fill: color, stroke: 'white', strokeWidth: '1' };
  switch (silhouette?.toLowerCase()) {
    case 'tee': return <path {...common} d="M12 4L16 6V10H14V20H10V10H8V6L12 4Z" />;
    case 'jeans': return <path {...common} d="M7 4H17L19 20H13L12 12L11 20H5L7 4Z" />;
    case 'hoodie': return <path {...common} d="M12 2C10 2 8 4 8 6L4 8V12H6V20H18V12H20V8L16 6C16 4 14 2 12 2Z" />;
    case 'sneakers': return <path {...common} d="M4 18L6 14L14 14L20 18V20H4V18Z" />;
    case 'jacket': return <path {...common} d="M12 4L18 6V20H6V6L12 4ZM12 6L9 20H15L12 6Z" />;
    default: return <rect {...common} x="6" y="7" width="12" height="10" rx="2" />;
  }
};

const CostumeDesigner: React.FC<CostumeDesignerProps> = ({ wardrobe, language, cache, setCache }) => {
  const [loading, setLoading] = useState(false);
  const [locationStr, setLocationStr] = useState<string | null>(null);

  const favorites = [...wardrobe].sort((a, b) => b.wearCount - a.wearCount).filter(i => i.wearCount > 0).slice(0, 3);

  useEffect(() => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((pos) => {
        setLocationStr(`Lat: ${pos.coords.latitude.toFixed(2)}, Lng: ${pos.coords.longitude.toFixed(2)}`);
      }, () => {
        setLocationStr("Global Style (Location Access Denied)");
      });
    }
  }, []);

  const refreshLookbook = async () => {
    if (loading) return;
    setLoading(true);
    try {
      const result = await getShoppingSuggestions(wardrobe, locationStr, language);
      if (result) {
        setCache({
          lastUpdated: new Date().toISOString(),
          products: result.products || [],
          advice: result.advice || ''
        });
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!cache && wardrobe.length > 0 && favorites.length > 0) {
      refreshLookbook();
    }
  }, [cache, wardrobe.length]);

  if (wardrobe.length === 0 || favorites.length === 0) {
    return (
      <div className="max-w-4xl mx-auto py-32 text-center space-y-8 animate-in fade-in">
        <div className="mx-auto w-32 h-32 bg-slate-100 rounded-[3.5rem] flex items-center justify-center text-slate-300">
          <ShoppingBag size={64} />
        </div>
        <h2 className="text-3xl font-black text-slate-800">No wear data yet!</h2>
        <p className="text-slate-500 font-medium">Log your daily outfits in the Stylist tab to unlock personalized shopping.</p>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto space-y-16 pb-32 px-4 animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-8 border-b border-slate-200 pb-12">
        <div className="space-y-3">
          <h2 className="text-5xl font-black text-slate-900 tracking-tighter flex items-center gap-4">
            <ShoppingBag className="text-indigo-600" size={48} /> Costume Designer
          </h2>
          <div className="flex items-center gap-3">
            <div className="px-3 py-1 bg-indigo-50 text-indigo-600 text-[10px] font-black uppercase rounded-lg border border-indigo-100 flex items-center gap-2">
               <MapPin size={12} /> {locationStr || "Locating..."}
