        >
          {loading ? <Loader2 className="animate-spin" size={20} /> : <RefreshCcw size={20} />}
          {cache ? 'Check for Updates' : 'Generate Lookbook'}
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-12">
        {/* Sidebar */}
        <div className="lg:col-span-1 space-y-8">
          <div className="bg-white p-8 rounded-[3rem] shadow-xl border border-slate-100 space-y-8">
            <h4 className="text-xl font-black text-slate-900 flex items-center gap-3">
              <Heart className="text-rose-500 fill-rose-500" size={24} /> Top Favorites
