import { GoogleGenAI, Type } from "@google/genai";
import { ClothingItem, ClothingCategory, ChatMessage, DesignerProduct } from "../types";

export const analyzeClothingImage = async (base64Image: string): Promise<any[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const prompt = `Analyze this image and identify all distinct clothing items present.
  Format the response as a JSON array of objects. Each object MUST have:
  - name: Unique name.
  - category: one of 'shirt', 'pants', 'accessory', 'shoes', 'other'
  - silhouette: 'tee', 'polo', 'hoodie', 'dress-shirt', 'tank', 'jeans', 'chinos', 'shorts', 'joggers', 'skirt', 'sneakers', 'boots', 'formal', 'sandals', 'watch', 'glasses', 'hat', 'scarf'
  - color: primary color name
  - hexColor: Valid CSS Hex Code.
  - material: likely material
  - pattern: e.g., solid, striped, etc.
  - style: casual, formal, etc.
  - season: spring, summer, fall, winter, or all-season
  - description: 1-sentence description.
  - box_2d: [ymin, xmin, ymax, xmax] coordinates.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image.split(',')[1] || base64Image } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              category: { type: Type.STRING, enum: Object.values(ClothingCategory) },
              silhouette: { type: Type.STRING },
              color: { type: Type.STRING },
              hexColor: { type: Type.STRING },
              material: { type: Type.STRING },
              pattern: { type: Type.STRING },
              style: { type: Type.STRING },
              season: { type: Type.STRING },
              description: { type: Type.STRING },
              box_2d: { type: Type.ARRAY, items: { type: Type.INTEGER } }
            },
            required: ["name", "category", "silhouette", "hexColor", "box_2d"]
          }
        }
      }
    });
    const text = response.text;
    return text ? JSON.parse(text) : [];
  } catch (e) {
    return [];
  }
};

export const getChatStylistResponse = async (
  wardrobe: ClothingItem[],
  history: ChatMessage[],
  userMessage: string,
  language: string = 'en'
): Promise<{ text: string; itemIds?: string[] } | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const contextPrompt = `You are a stylish best friend. Use the user's wardrobe to recommend outfits.
  WARDROBE: ${JSON.stringify(wardrobe.map(i => ({ id: i.id, name: i.name, category: i.category, color: i.color })))}

  Format the response as JSON:
  {
    "text": "Your friendly message in ${language}",
    "itemIds": ["id1", "id2"]
  }`;

  const contents = [
    { role: 'user', parts: [{ text: contextPrompt }] },
    ...history.map(msg => ({
      role: msg.role === 'model' ? 'model' : 'user',
      parts: [{ text: msg.text }]
    })),
    { role: 'user', parts: [{ text: userMessage }] }
  ];

  try {
    const response = await ai.models.generateContent({
      model,
      contents: contents as any,
      config: {
        responseMimeType: "application/json",
      }
    });
    return response.text ? JSON.parse(response.text) : null;
  } catch (e) {
    return null;
  }
};

