  const favorites = [...wardrobe].sort((a, b) => b.wearCount - a.wearCount).slice(0, 3);
  const styleSummary = wardrobe.map(i => `${i.color} ${i.style} ${i.category}`).join(', ');

  const prompt = `You are the "Master Costume Designer".

  TASK:
  Find exactly 10 REAL, BUDGET-FRIENDLY products using Google Search.

  CONSTRAINTS:
  1. LOCATION & CURRENCY: User is at ${location || 'Global'}. If in India, use INR (₹). If USA, use USD ($).
  2. BUDGET FOCUS: Prioritize high-value, affordable clothes from Amazon, Flipkart, Myntra, Ajio, or Uniqlo. Find the LOWEST prices.
  3. URL VALIDITY: Use REAL search grounding URLs. NO 404s. Ensure URLs lead to active products.
  4. FEEDBACK MEMORY: The user gave this feedback on previous suggestions: "${previousFeedback.join('; ')}". AVOID things they disliked.

  OUTPUT (JSON ONLY):
  {
    "advice": "Bold trend advice for ${location} in ${language}.",
    "products": [
      {
        "id": "unique_string",
        "name": "Specific Product Name",
        "price": "₹699",
        "store": "Amazon",
        "url": "FUNCTIONAL_URL",
        "imageUrl": "DIRECT_IMAGE_LINK",
        "reason": "Explain CLEARLY and BOLDRY why this fits their closet.",
        "silhouette": "tee/jeans/hoodie/sneakers/boots/jacket",
        "hexColor": "#hex"
      }
    ]
  }

  Closet: ${styleSummary}. 
  Likes: ${favorites.map(f => f.name).join(', ')}.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
      }
    });

    return response.text ? JSON.parse(response.text) : null;
  } catch (e) {
    console.error("Designer API Error:", e);
    return null;
  }
};

